import{_ as e,o as s,c as i,af as t}from"./chunks/framework.5D6DWnkB.js";const u=JSON.parse('{"title":"OECT (Armbian) 挂载外置硬盘不休眠的排障与修复实战","description":"","frontmatter":{},"headers":[],"relativePath":"hardware/oect-hdparm-sleep.md","filePath":"hardware/oect-hdparm-sleep.md"}'),d={name:"hardware/oect-hdparm-sleep.md"};function p(o,a,l,h,n,r){return s(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="oect-armbian-挂载外置硬盘不休眠的排障与修复实战" tabindex="-1">OECT (Armbian) 挂载外置硬盘不休眠的排障与修复实战 <a class="header-anchor" href="#oect-armbian-挂载外置硬盘不休眠的排障与修复实战" aria-label="Permalink to &quot;OECT (Armbian) 挂载外置硬盘不休眠的排障与修复实战&quot;">​</a></h1><p>前几天搞定了一台闲置的网心云 OECT，底层刷入了 Armbian 25.5.1，并在上面跑起了 CasaOS。为了把它改造成家用轻量 NAS 和备份中心，我将一块 2T 西数硬盘外挂了上去（目前作为 PVE 和 OpenClaw 的滚动备份盘）。</p><p>但很快发现一个问题：这块 2T 硬盘它<strong>不休眠</strong>。不管有没有数据读写，它就像打了鸡血一样全天候运转。虽然做 NAS 的盘本该如此，但这毕竟是家用闲置设备的废物利用，没必要让它 24 小时空转消耗寿命，听着也烦。</p><p>所以今天花了一点时间，把这个“不眠之症”给治了。在此记录一下排查与修复的过程。</p><h2 id="_1-确认病因-谁在阻止硬盘休眠" tabindex="-1">1. 确认病因：谁在阻止硬盘休眠？ <a class="header-anchor" href="#_1-确认病因-谁在阻止硬盘休眠" aria-label="Permalink to &quot;1. 确认病因：谁在阻止硬盘休眠？&quot;">​</a></h2><p>Linux 下控制硬盘休眠最常见的工具是 <code>hdparm</code>。</p><p>一开始我直接尝试用 <code>hdparm -y /dev/sda</code> 让它强制进入待机模式，结果发现：它确实停转了，但<strong>不到 10 秒钟，又重新启动了</strong>。</p><p>这说明系统里有后台进程在频繁读写（或者唤醒）这块硬盘。常见嫌疑犯包括：</p><ul><li>系统日志守护进程 (syslog, journald 等)</li><li>SMART 监控 (smartd)</li><li>CasaOS 或挂载在上面的 Docker 容器 (比如易有云 <code>linkease</code>) 定时扫描</li></ul><h2 id="_2-排查抓鬼-揪出幕后黑手" tabindex="-1">2. 排查抓鬼：揪出幕后黑手 <a class="header-anchor" href="#_2-排查抓鬼-揪出幕后黑手" aria-label="Permalink to &quot;2. 排查抓鬼：揪出幕后黑手&quot;">​</a></h2><p>为了找出具体是哪个进程在唤醒硬盘，我们可以借助 <code>fatrace</code> 或者 <code>iotop</code>，也可以通过开启内核的 block dump。</p><p>最简单的办法，用 <code>iotop -o</code> 观察。</p><p>结果发现，主要是我在上面跑的 <code>linkease</code> (易有云) Docker 容器，以及 CasaOS 本身的某些状态轮询在作祟。</p><p>由于这台设备的主要用途是每天凌晨 04:00 和 05:00 接收 PVE 与主控机的备份压缩包，平时白天它的读写需求极低，我决定采用一种更强硬且智能的休眠策略。</p><h2 id="_3-制定休眠策略-hdparm-规则" tabindex="-1">3. 制定休眠策略：hdparm 规则 <a class="header-anchor" href="#_3-制定休眠策略-hdparm-规则" aria-label="Permalink to &quot;3. 制定休眠策略：hdparm 规则&quot;">​</a></h2><p>最终，我选择配置 <code>hdparm</code> 规则，设定硬盘在空闲 10 分钟（600秒）后自动停转待机。</p><h3 id="_3-1-测试休眠指令" tabindex="-1">3.1 测试休眠指令 <a class="header-anchor" href="#_3-1-测试休眠指令" aria-label="Permalink to &quot;3.1 测试休眠指令&quot;">​</a></h3><p>先用命令测试（假设你的硬盘是 <code>/dev/sda</code>）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hdparm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 120</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/sda</span></span></code></pre></div><p><em>注：<code>-S</code> 后面的数字是休眠时间，单位是 5 秒（120 x 5 = 600 秒，即 10 分钟）。</em></p><h3 id="_3-2-固化配置到-udev-规则" tabindex="-1">3.2 固化配置到 udev 规则 <a class="header-anchor" href="#_3-2-固化配置到-udev-规则" aria-label="Permalink to &quot;3.2 固化配置到 udev 规则&quot;">​</a></h3><p>因为每次重启或者重新插拔硬盘，<code>hdparm</code> 的设置可能会失效。最好的办法是写进 udev 规则里，让它成为系统底层铁律。</p><p>创建并编辑规则文件：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nano</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/udev/rules.d/50-hdparm.rules</span></span></code></pre></div><p>填入以下内容：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ACTION==&quot;add|change&quot;, KERNEL==&quot;sda&quot;, ATTR{queue/rotational}==&quot;1&quot;, RUN+=&quot;/sbin/hdparm -S 120 /dev/sda&quot;</span></span></code></pre></div><p>这个规则的意思是：当系统检测到添加或改变一个旋转型（非 SSD）硬盘设备 <code>sda</code> 时，自动执行休眠设定（空闲 10 分钟停转）。</p><p>保存后，重新加载 udev 规则：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> udevadm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> control</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --reload-rules</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> udevadm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> trigger</span></span></code></pre></div><h2 id="_4-优化-减少无谓的唤醒" tabindex="-1">4. 优化：减少无谓的唤醒 <a class="header-anchor" href="#_4-优化-减少无谓的唤醒" aria-label="Permalink to &quot;4. 优化：减少无谓的唤醒&quot;">​</a></h2><p>光设置了休眠还不够，为了防止刚休眠就被唤醒，我还做了一点优化：</p><ul><li>将一些不需要频繁写盘的日志路径迁移到了内存文件系统 (tmpfs)。</li><li>在 CasaOS 中，非必要的应用如果在后台频繁扫描 <code>/mnt/Storage1</code>（我的 2T 硬盘挂载点），就将其休眠或者调整扫描周期。</li></ul><h2 id="结语" tabindex="-1">结语 <a class="header-anchor" href="#结语" aria-label="Permalink to &quot;结语&quot;">​</a></h2><p>折腾完之后，现在这块 2T 西数硬盘终于学会了“劳逸结合”。平时安安静静地待机停转，到了凌晨 4、5 点接收备份任务时再自动苏醒干活。</p><p>废物利用的精髓不仅在于“能用”，更在于“好用”和“稳定”。希望这篇排障记录能帮到同样在玩 Armbian / CasaOS 外挂硬盘的朋友。</p>`,35)])])}const k=e(d,[["render",p]]);export{u as __pageData,k as default};
